var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"성황청 지원 함선, <color=#ffd34c>피에타</color> 함교","JPN":"聖皇庁支援艦船、<color=#ffd34c>ピエタ</color>艦橋","ENG":"Holy Curia Support ship <color=#ffd34c>Pieta</color>, Bridge","TWN":"聖皇廳支援艦船，<color=#ffd34c>聖殤</color>號艦橋"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"지정된 봉쇄 좌표의 좌표값 입력…….","JPN":"指定の封鎖座標を入力……","ENG":"Entering the designated sealing coordinates...","TWN":"輸入指定封鎖座標的座標值……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"쓰러스터 전부 개방! 이터니움 드라이브 기동률 15%, 34%, 72%……!","JPN":"スラスター全開放！　エタニウムドライブ起動率15％、34％、72％……！","ENG":"All thrusters open! Eternium Drive activation rate at 15%, 34%, 72%...!","TWN":"開放所有推進器！永恆之金引擎機動率15%，34%，72%……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"피에타! 주님의 은총 아래, 다이브하겠습니다!","JPN":"ピエタ！　主の恩寵の元、ダイブします！","ENG":"Pieta! Under God's grace, commencing dive!","TWN":"聖殤！在主的恩賜下，進行躍入！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"다이브 완료.","JPN":"ダイブ完了。","ENG":"Dive complete.","TWN":"躍入完成。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"일반 항행 모드로 전환합니다.","JPN":"一般航行モードに切り替えます。","ENG":"Switching to normal navigation mode.","TWN":"切換到正常航行模式。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"집행사제님, 지정된 봉쇄 좌표에 진입 완료하였습니다!","JPN":"執行司祭様、指定の封鎖座標に進入しました！","ENG":"We've entered the specified sealing coordinates, ma'am!","TWN":"執行祭司，已進入指定封鎖座標！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심도가 무척 깊군요. 어떤 일이 일어나도 이상하지 않아요.","JPN":"深度が深いですね。ここでは何が起きてもおかしくない場所です。","ENG":"It is extremely deep. Anything can happen here.","TWN":"這個深度，發生什麼樣的事都不會覺得奇怪。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자매님, 적성 반응 확인부터 부탁드리겠습니다.","JPN":"敵性反応の確認からお願いいたします。","ENG":"Sister, please check if there are any hostiles being detected.","TWN":"姊妹，請先確認是否有敵人反應。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"함선 안에 예배당도 있는 거야?","JPN":"艦船の中に礼拝堂もあるのかよ？","ENG":"There's even a chapel inside the ship?","TWN":"艦船裡面也有禮拜堂嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 살다살다 성황청 함선을 빌려 타게 될 줄은 몰랐네.","JPN":"ったく、聖皇庁の艦船に乗ることになるとはな。","ENG":"Blimey. Who would've thought I'd be on a Holy Curia ship, eh?","TWN":"真是的，沒想到我有生之年會坐上聖皇廳的艦船。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"원래 불신자들은 탑승할 수 없는 함선입니다만.","JPN":"本来なら不信者は搭乗できない艦船ですが……","ENG":"Normally, we do not allow nonbelievers to be on board.","TWN":"非信徒本是無法乘坐這個艦船的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"한시가 급한 일이니, 특별히 동승을 허가해드렸습니다. 나중에 고해성사라도 해야겠군요.","JPN":"一刻を争う状況ですので、特別同乗を許可しました。告解扱いです。","ENG":"But since this is an urgent matter, I will especially allow it this time. I should make a confession about this later.","TWN":"但現在刻不容緩，所以特意准你同乘。以後再對此進行懺悔吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회 측 추종자인 당신은 필히 소속과 신분을 숨기도록 하세요.","JPN":"あなたは学会側の人間ですから、所属と身分が認知されないように気をつけてください。","ENG":"Follower of the Society, you must hide your identity no matter what.","TWN":"你身為學會方面的追隨者，請務必隱瞞所屬和身分。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그럼~ 내가 레지나 명령으로 여기 왔다는 건 아무한테도 말 안 할게!","JPN":"もちろん～レジーナの命令でここに来てるって、誰にも言わないから！","ENG":"Then, I won't tell a soul that I'm here on Regina's orders!","TWN":"當然了～我才不會告訴任何人我是奉蕾佳娜命令來到這裡的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하아, 당신과 이야기를 나누고 있으면 시스터 루퍼가 그리워질 지경이군요.","JPN":"はあ……あなたと会話していると、シスター・ルーパーが恋しくなります。","ENG":"*Sigh.* Talking with you makes me miss Sister Looper.","TWN":"哈啊，和你聊天，總是能讓我想念洛珀姊妹。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"집행사제님, 방패 용병단 1개 중대 성무 집행 준비를 마쳤습니다.","JPN":"執行司祭様、盾傭兵団1個中隊の聖務執行準備が整いました。","ENG":"Ma'am, a company of Shield Mercenary has finished preparations for the sacred mission.","TWN":"執行祭司，盾牌傭兵團的一個中隊已做好執行聖務的準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L38_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"언제든 말씀만 해주십시오. 주님의 이름 아래 싹 쓸어버리겠습니다.","JPN":"いつでも指示を出してください。主の名の元に全部蹴散らしてみせます。","ENG":"Just say the word. We'll cleanse the place under the Lord's name.","TWN":"請隨時下令。我們會以神的名義，將敵人全數清除。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오늘 성무의 주요 목적은 수색입니다. 되도록 전투는 피해주세요.","JPN":"本日の聖務の主な目的は捜索です。なるべく戦闘は避けるように。","ENG":"The objective of today's sacred mission is reconnaissance. Please try to refrain from combat.","TWN":"今天聖務的主要目的是搜索，所以要盡量避免戰鬥。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그보다 버넷 요원. 기관의 지원은 언제쯤 도착하죠?","JPN":"それより、エージェント・バーネット。機関の支援はいつ頃着く予定ですか？","ENG":"And Agent Burnett. When do you think the Institution's reinforcements will arrive?","TWN":"對了，伯內特，機關的支援什麼時候能到？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어……? 어어……?","JPN":"え……？　ええと……？","ENG":"Wha...? Huh...?","TWN":"呃……？呃呃……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그걸 왜 나한테 물어?","JPN":"なんでそれを俺に聞く？","ENG":"Why are you asking me that?","TWN":"那個為什麼要問我？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 이 자리에 달리 누가 있다는 거죠?","JPN":"あなた以外に、誰に聞けというのですか？","ENG":"Then, who else shall I ask?","TWN":"那麼，在這裡還有別人可以問嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다른 심의회 인원들은 최고 등급 재난경보에 의거, 시민들의 안전을 위해 동원되었습니다.","JPN":"他の審議会員は最高ランクの災難警報により、市民の安全を確保するために動員されています。","ENG":"The other Council members were deployed to protect the citizens under the highest-level disaster alert.","TWN":"因為最高等級的災難警報，其他議會的成員均被調動以確保市民安全。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 저희 쪽에서 급하게 모을 수 있는 인원은 이 정도뿐이라는 뜻이죠.","JPN":"私たちの方で早急に集められる人数はこの程度だけということです。","ENG":"Thus, this was the most manpower we could gather at a moment's notice.","TWN":"也就是說，我們這邊能緊急召集的人員只有這些。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 중 카운터는 저희 둘뿐입니다.","JPN":"その中でカウンターは私たち二人のみ。","ENG":"Among them, we both are the only Counters.","TWN":"其中制裁者只有我們二個人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이래서는 돌발상황이 발생했을 때 대처할 수가 없어요.","JPN":"これでは、予期せぬ事態が起きた場合太刀打ちできません。","ENG":"At this rate, we will have no means to deal with emergency situations if they occur.","TWN":"這樣下去，如果發生突發情況，我們便無法應對。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"애초에 성배가 있을 것이라고 추측되는 이 좌표를 넘긴 건, 기관 측이었을 텐데요?","JPN":"そもそも聖杯があると推測されるこの場所の座標を送ってきたのは、機関側だったはずです。","ENG":"Also, the coordinates for where the Holy Grail is assumed to be were from the Institution, were they not?","TWN":"當初把推測聖杯所在之處的座標交給我們的，就是機關吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 무슨 뚱딴지 같은 소리를 하는 거야, 종이 수녀?","JPN":"おい、何訳わからないこと言ってるんだ、ペーパーシスター。","ENG":"Blimey. What are you even talking about, paper nun?","TWN":"真是的。你在說什麼傻話呢，紙修女？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터가 우리 둘뿐이라니. 그때 분명 같이…….","JPN":"カウンターが俺たち二人だけって、あの時一緒に……","ENG":"We both are the only Counters? There's another...","TWN":"什麼叫制裁者只有我們二個人，當時明明一起……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"작전을…….","JPN":"作戦を……","ENG":"Another...","TWN":"作戰的……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"왜 그러시죠? 안색이 좋지 않습니다만?","JPN":"どうかしましたか？　顔色が優れないようですが。","ENG":"Is something wrong? You do not look so good.","TWN":"怎麼了？你的臉色好像不太好？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이상해…….","JPN":"変だ。","ENG":"Something's not right...","TWN":"好奇怪……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭔가, 뭔가…… 아주 중요한 걸 잊어버린 것 같은 느낌이 들어.","JPN":"何か、何か……とても大事なことを忘れてしまった気がする。","ENG":"I feel like... I'm forgetting something extremely important.","TWN":"我總感覺……忘記了很重要的東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"중요한 것? 무슨 말씀이시죠?","JPN":"大事なこと？　どういうことですか？","ENG":"Important? What do you mean by that?","TWN":"重要的東西？你在說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 걸……. 잊어버릴 리가 없는데……?","JPN":"そんなの……忘れるはずがないのに……？","ENG":"There's no way... I could forget something like this...","TWN":"怎麼可能……會忘記呢……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"누구지……? 작전을 떠올렸던 사람이……?","JPN":"誰だ……？　作戦を思いついた人は……？","ENG":"Who was it...? The one who came up with this plan...?","TWN":"是誰……？是誰提起了作戰……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어라? 그럼 나한테 맡겨볼래?","JPN":"あっ、じゃあアタシに任せてみる？","ENG":"Oh? Do you want me to help?","TWN":"喔喔，失憶？交給我怎麼樣？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"급성 기억 상실에는 물리치료가 직빵이거든!","JPN":"急性記憶喪失には、物理的な治療が効くんだよ！","ENG":"Physical therapy works best for acute memory loss!","TWN":"急性記憶喪失，用物理治療馬上就能治好！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L26_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"집행사제님! 적성 반응 다수!","JPN":"執行司祭様！　敵性反応を多数確認！","ENG":"Ma'am! Multiple hostiles detected!","TWN":"執行祭司！檢測到了多數敵人反應！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"불경한 침식체들이 함선에 달라붙고 있습니다!","JPN":"不敬な侵食体が艦船に張り付いています！","ENG":"Those heathen C.O.s are latching onto the ship!","TWN":"懷有敵意的侵蝕體正附著在艦船上！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"함선의 외부 모니터를 연결해주세요.","JPN":"艦船の外部モニターを繋いでください。","ENG":"Connect me to the ship's external feed.","TWN":"請連接艦船的外部顯示器。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>불완전한</color> 지식, <b>불완</b>전한 존<color=#ff3636>재들이 성</color>찬을 통해 완<b>전해</b>지리니......","JPN":"<color=#ff3636>不完全な</color>知識、<b>不完</b>全な存<color=#ff3636>在たちが聖</color>餐により完<b>全体と</b>なる……","ENG":"T<color=#ff3636>he feast</color> will <b>com</b>plete the imperfect <color=#ff3636>knowledge</color> and perfect the <b>imp</b>erfect beings.","TWN":"<color=#ff3636>不完整的</color>知識，<b>不完整</b>的存在將透過<color=#ff3636>盛宴</color>變得完整<b></b>……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"4, 8, 12, 17……!","JPN":"4、8、12、17……！","ENG":"4... 8... 12... 17...!","TWN":"4，8，12，17……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"함선에 달라붙는 적성 개체! 계속 증가하고 있습니다!","JPN":"艦船に張り付く敵性個体が増えています！","ENG":"The number of hostiles latching onto the ship is increasing!","TWN":"附著在艦船上的敵人個體！一直在增加！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"집행사제님! 함선의 출력이 저하되고 있습니다!","JPN":"執行司祭様！　艦船の出力が低下しています！","ENG":"Ma'am! The ship's output is decreasing as well!","TWN":"執行祭司！艦船的功率正在下降！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"아무래도 동력부에 잔해가 빨려 들어간 것 같습니다!","JPN":"動力部に残骸が吸い込まれてしまったようです！","ENG":"It seems that some Remains got sucked into the engine!","TWN":"好像是殘骸進入了動力部！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런…… 기습이로군요.","JPN":"奇襲ですね。","ENG":"This... is an ambush.","TWN":"糟了……是突襲。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐가 어떻게 된 거야? 잔해한테 비행 능력 같은 건 없을 텐데?","JPN":"何がどうなってんだ？　残骸に飛行能力なんかないはずだろう？","ENG":"What's going on? Remains don't have any flying capabilities, right?!","TWN":"怎麼回事？殘骸應該沒有飛行能力吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그동안 학회가 잔해를 다루는 방식을 생각해보면, 비행능력 같은 게 아닐 겁니다.","JPN":"学会の残骸の扱い方法を考えてみると、これは飛行能力などではないでしょう。","ENG":"Looking back at how the Society handles Remains, this is probably not them flying.","TWN":"考慮到學會此前處理殘骸的方式，應該不是什麼飛行能力。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아무래도 투석기 같은 것으로 잔해를 쏘아 올리는 것 같군요.","JPN":"どうやら投石機のようなもので、残骸を打ち上げているようです。","ENG":"I believe they are being catapulted toward us.","TWN":"看來是用投石機之類的東西把殘骸拋了上來。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쏘아 올린다고? 무슨 그딴 막무가내 작전을……!?","JPN":"打ち上げる？　そんな無茶な作戦を……！？","ENG":"Catapulted? What kind of reckless operation is that...?!","TWN":"投石機？哪有這麼野蠻的作戰……？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"막무가내처럼 보여도 이런 작전이 가능하다는 뜻은.","JPN":"無茶に見えても、こんな作戦が実行できているということは……","ENG":"It may be reckless, but seeing how they are able to execute an operation like this...","TWN":"雖然看起來很野蠻，但能實現這種作戰便說明……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"적어도 대대급 이상의 병력이 이 곳에 대기하고 있다는 맥락을 읽을 수 있군요.","JPN":"大隊規模以上の兵力がここに待機しているという意味になりますね。","ENG":"The context of this situation shows that they have a battalion of troops waiting for us.","TWN":"至少有大隊級以上兵力在這裡待命。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 학회의 잔당들이 아직도 그렇게나 많단 말이야?","JPN":"なんだと？　まだ学会の残党がそんなにいるってことか？","ENG":"What? You mean there are still that many Society remnants left?","TWN":"什麼？學會的餘黨還剩下那麼多嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아마 기관을 습격했던 병력이 이곳에 전부 모였다고 생각됩니다.","JPN":"おそらく、機関を襲撃した兵力がすべてここに集まっているのでしょう。","ENG":"I think all the troops that attacked the Institution have gathered here.","TWN":"恐怕，襲擊機關的兵力，都聚集在這裡了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"역으로 생각하면, <color=#ffd34c>무언가</color>를 지키겠다는 의도가 읽히는군요.","JPN":"逆に、<color=#ffd34c>何か</color>を守ろうとする強い意思のようなものを感じます。","ENG":"Thinking about it the other way around, it could be read as their attempt to protect <color=#ffd34c>something</color>.","TWN":"反過來看，可以看出他們想要守護<color=#ffd34c>某種</color>東西。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아, 그럼 우리가 제대로 찾아왔다는 뜻이네.","JPN":"よし、じゃあ俺たちが正しかったってことだな。","ENG":"All right. Then that means we came to the right place.","TWN":"好，那就說明我們找對了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어떡할 거야, 수녀님? 이러다간 싸우기도 전에 함선이 추락해버릴 지도 모른다고?","JPN":"どうする、シスターさん？　このままだと戦う前に艦船が落ちちゃうよ？","ENG":"What's our next move, Sister? The ship might crash before we even start fighting at this rate.","TWN":"修女，你打算怎麼辦？這樣下去，說不定還沒打起來，艦船就已經墜落了？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"알고 있습니다.","JPN":"わかっています。","ENG":"I am aware.","TWN":"我知道。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"전 인원, 지금부터 피에타는 비상 착륙 절차에 돌입합니다!","JPN":"全員、これよりピエタは非常着陸モードに入ります！","ENG":"All hands, commence Pieta's emergency landing, immediately!","TWN":"全體人員，從現在開始——聖殤號將進行緊急著陸！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 차례다! 방패 용병단! 모두 교전 준비!","JPN":"俺たちの番だ！　盾傭兵団！　交戦の準備を！","ENG":"It's our turn now! Shield Mercenary! Get ready for combat!","TWN":"輪到我們了！盾牌傭兵團！全體準備交戰！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L18_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"몸이 근질근질 하던 참입니다. 맡겨만 주세요!","JPN":"そろそろ体がうずいていたとこです！　任せてください！","ENG":"I'm already itching for a kill. Leave it to us!","TWN":"身體正發癢呢，就交給我們吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"현재, 적의 규모를 짐작할 수 없는 상황입니다.","JPN":"現在、敵の規模は推測できません。","ENG":"Currently, the enemy's size is unknown.","TWN":"目前，敵方的規模不可估量。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주님의 가호 아래, 모두 침착하게 전투에 임하도록 하세요.","JPN":"主の加護の元に、皆冷静に戦闘へ挑むようにしてください。","ENG":"Under the Lord's grace, fight with caution.","TWN":"在主的保佑下，請大家沉著投入作戰。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};